import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import DefiDevelopmentScreen from "@screens/defi-development-company";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const DefiDevelopmentPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "DeFi Development Company", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.defiDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "An organization that develops DeFi, creates safe and scalable decentralized financial applications, such as smart contracts, DApps, staking, and lending applications.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1543",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is DeFi Development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The development of DeFi refers to the creation of applications on the blockchain in the field of decentralized finance that allow performing services such as lending, borrowing, trading, and staking without intermediaries.",
            },
          },
          {
            "@type": "Question",
            name: "What is a DeFi developer?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A developer in DeFi is a professional in the blockchain industry who is involved in the creation of decentralized finance applications, smart contracts, and protocols to lending, trading, and staking among other financial offerings without middlemen.",
            },
          },
          {
            "@type": "Question",
            name: "How does DeFi make money?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The sources of revenue in DeFi are transaction fees, lending and borrowing interest spreads, staking fees, liquidity pool fees, token issuance, and protocol service fees.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <DefiDevelopmentScreen db={db} />
    </Layout_v2>
  );
};

export default DefiDevelopmentPage;

export const queryData = graphql`
  query MyQuery {
    defiDevImg: file(relativePath: { eq: "defi-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "defi-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
